<?php $editing = !empty($editTask); ?>
<div class="page-header"><div><h2>Tasks</h2><p>Follow-ups, ownership, due dates, and workload management across the CRM.</p></div></div>
<div class="grid-two">
<div class="card"><h3><?= $editing ? 'Edit Task' : 'Add Task' ?></h3><form method="post" class="stack-form"><?= csrf_field() ?><input type="hidden" name="action" value="<?= $editing ? 'update' : 'create' ?>"><?php if ($editing): ?><input type="hidden" name="id" value="<?= e((string)$editTask['id']) ?>"><?php endif; ?><input name="task_name" placeholder="Task Name" value="<?= e($editTask['task_name'] ?? '') ?>" required><input name="related_type" placeholder="Related Type" value="<?= e($editTask['related_type'] ?? '') ?>"><input name="related_name" placeholder="Related Record" value="<?= e($editTask['related_name'] ?? '') ?>"><select name="assigned_user_id"><option value="">Assigned Owner</option><?php foreach ($assignableUsers as $user): ?><option value="<?= e((string)$user['id']) ?>" <?= ((string)($editTask['assigned_user_id'] ?? '') === (string)$user['id']) ? 'selected' : '' ?>><?= e($user['full_name']) ?> · <?= e($user['role']) ?></option><?php endforeach; ?></select><select name="priority_level"><?php foreach (['Low','Normal','High','Urgent'] as $p): ?><option value="<?= e($p) ?>" <?= (($editTask['priority_level'] ?? 'Normal')===$p)?'selected':''; ?>><?= e($p) ?></option><?php endforeach; ?></select><input type="date" name="due_date" value="<?= e($editTask['due_date'] ?? '') ?>"><select name="status"><?php foreach (['Open','In Progress','Completed','Blocked'] as $s): ?><option value="<?= e($s) ?>" <?= (($editTask['status'] ?? 'Open')===$s)?'selected':''; ?>><?= e($s) ?></option><?php endforeach; ?></select><textarea name="notes" placeholder="Notes"><?= e($editTask['notes'] ?? '') ?></textarea><div class="actions"><button type="submit"><?= $editing ? 'Save Changes' : 'Create Task' ?></button><?php if ($editing): ?><a class="btn-muted" href="index.php?page=tasks">Cancel</a><?php endif; ?></div></form></div>
<div class="card"><h3>Task Board</h3><table><thead><tr><th>Task</th><th>Status</th><th>Priority</th><th>Assigned</th><th></th></tr></thead><tbody><?php foreach ($tasks as $row): ?><tr><td><?= e($row['task_name']) ?><div class="muted"><?= e($row['related_type']) ?> · <?= e($row['related_name']) ?></div></td><td><span class="tag"><?= e($row['status']) ?></span></td><td><?= e($row['priority_level']) ?></td><td><?= e($row['assigned_to']) ?></td><td class="table-actions"><a href="index.php?page=tasks&id=<?= e((string)$row['id']) ?>">Edit</a><?php if (App\Core\Auth::can('tasks','delete')): ?><form method="post" onsubmit="return confirm('Delete this task?');"><?= csrf_field() ?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?= e((string)$row['id']) ?>"><button class="btn-danger" type="submit">Delete</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div>
</div>
